--1. Create the file format
CREATE EXTERNAL FILE FORMAT parquet_format
WITH
(
    FORMAT_TYPE = PARQUET
);

--2. Create the data source - bankdata_source_mi

--3. Create CETAS table
CREATE EXTERNAL TABLE ext_bankdata_cetas
WITH
(
    LOCATION = 'optimized/bank_txns',
    DATA_SOURCE = bankdata_source_mi,
    FILE_FORMAT = parquet_format
)
AS
SELECT * FROM ext_bankdata;

select * from ext_bankdata_cetas;

--Views
create or alter VIEW vw_ext_bankdata
AS
select cust_id,amount,branch from ext_bankdata_cetas where region = 'EAST';

select * from vw_ext_bankdata;

select * from INFORMATION_SCHEMA.TABLES where TABLE_TYPE = 'VIEW';

--Schema
create schema bankschema;

create or alter VIEW bankschema.vw_ext_bankdata1
AS
select cust_id,amount,branch from ext_bankdata_cetas where region = 'EAST';
